const embedding = $json.data?.[0]?.embedding || [];

return {
  pipeline: [
    {
      $vectorSearch: {
  index: "vector_index",
  path: "embedding",
  queryVector: embedding,
  numCandidates: 30,
  limit: 4
}
},
{
  $project: {
    _id: 0,
    erro: 1,
    causa: 1,
    solucao: 1,
    score: { $meta: "vectorSearchScore" }
  }
}
  ],
  question: $node["[Input] Normalize User Question"].json.question
};

const docs = $input.all()
  .slice(0, 3)
  .map((item, index) => {
    const doc = item.json;

    const codigo = doc.codigo ?? doc.rejeicao ?? "";
    const erro = doc.erro ?? "";
    const causa = doc.causa ?? "";
    const solucao = doc.solucao ?? "";

    const partes = [`Resultado ${index + 1}`];

    if (codigo) partes.push(`Código: ${codigo}`);
    if (erro) partes.push(`Erro: ${erro}`);
    if (causa && causa !== "—") partes.push(`Causa: ${causa}`);
    if (solucao && solucao !== "—") partes.push(`Solução: ${solucao}`);

    return partes.join("\n");
  })
  .filter(texto => texto.trim() !== "");

return [
  {
    json: {
      context: docs.join("\n\n"),
      question: $node["[Input] Normalize User Question"].json.question,
      source: docs.length ? "vector" : "no_match"
    }
  }
];
